'use strict';

/**
 * animation-injector.js — post-processor that injects click-to-appear
 * animations into a .pptx file generated by slide-renderer.js.
 *
 * Usage: node animation-injector.js input.pptx manifest.json [output.pptx]
 *
 * If output is omitted, the input file is overwritten.
 *
 * How it works:
 * 1. Reads the .pptx (a ZIP of XML files)
 * 2. Reads the animation manifest (which shapes/paragraphs to animate)
 * 3. For each slide with animations, parses the slide XML, finds the
 *    target shape by name, and injects <p:timing> OOXML for per-paragraph
 *    "Appear on Click" entrance animations.
 * 4. Writes the modified .pptx
 *
 * Each click group in the manifest becomes a separate click event.
 * Paragraphs within the same click group appear together on one click.
 */

const fs = require('fs');
const JSZip = require('jszip');

// ---------------------------------------------------------------------------
// Generate <p:timing> XML for a slide's animations
//
// animations: array of { spid: number, clicks: number[][] }
//   where each click is an array of 0-based paragraph indices
// ---------------------------------------------------------------------------
function generateTimingXml(animations) {
  let idCounter = 1;
  const nextId = () => idCounter++;

  // Collect all click events across all shapes, preserving order
  const allClicks = [];
  for (const anim of animations) {
    for (const paragraphs of anim.clicks) {
      allClicks.push({ spid: anim.spid, paragraphs });
    }
  }

  if (allClicks.length === 0) return '';

  const tmRootId = nextId();
  const mainSeqId = nextId();

  let clickParsXml = '';

  for (const click of allClicks) {
    const outerParId = nextId();
    // Each paragraph in this click group gets its own inner animation node
    let innerParsXml = '';

    for (const paraIdx of click.paragraphs) {
      const midParId = nextId();
      const effectId = nextId();
      const setId = nextId();

      innerParsXml += `
              <p:par>
                <p:cTn id="${midParId}" fill="hold">
                  <p:stCondLst>
                    <p:cond delay="0"/>
                  </p:stCondLst>
                  <p:childTnLst>
                    <p:par>
                      <p:cTn id="${effectId}" presetID="1" presetClass="entr" presetSubtype="0" fill="hold" nodeType="clickEffect">
                        <p:stCondLst>
                          <p:cond delay="0"/>
                        </p:stCondLst>
                        <p:childTnLst>
                          <p:set>
                            <p:cBhvr>
                              <p:cTn id="${setId}" dur="1" fill="hold">
                                <p:stCondLst>
                                  <p:cond delay="0"/>
                                </p:stCondLst>
                              </p:cTn>
                              <p:tgtEl>
                                <p:spTgt spid="${click.spid}">
                                  <p:txEl>
                                    <p:pRg st="${paraIdx}" end="${paraIdx}"/>
                                  </p:txEl>
                                </p:spTgt>
                              </p:tgtEl>
                              <p:attrNameLst>
                                <p:attrName>style.visibility</p:attrName>
                              </p:attrNameLst>
                            </p:cBhvr>
                            <p:to>
                              <p:strVal val="visible"/>
                            </p:to>
                          </p:set>
                        </p:childTnLst>
                      </p:cTn>
                    </p:par>
                  </p:childTnLst>
                </p:cTn>
              </p:par>`;
    }

    clickParsXml += `
          <p:par>
            <p:cTn id="${outerParId}" fill="hold">
              <p:stCondLst>
                <p:cond delay="indefinite"/>
              </p:stCondLst>
              <p:childTnLst>${innerParsXml}
              </p:childTnLst>
            </p:cTn>
          </p:par>`;
  }

  const prevNextId1 = nextId();
  const prevNextId2 = nextId();

  return `<p:timing>
  <p:tnLst>
    <p:par>
      <p:cTn id="${tmRootId}" dur="indefinite" restart="never" nodeType="tmRoot">
        <p:childTnLst>
          <p:seq concurrent="1" nextAc="seek">
            <p:cTn id="${mainSeqId}" dur="indefinite" nodeType="mainSeq">
              <p:childTnLst>${clickParsXml}
              </p:childTnLst>
            </p:cTn>
            <p:prevCondLst>
              <p:cond evt="onPrev" delay="0">
                <p:tgtEl><p:sldTgt/></p:tgtEl>
              </p:cond>
            </p:prevCondLst>
            <p:nextCondLst>
              <p:cond evt="onNext" delay="0">
                <p:tgtEl><p:sldTgt/></p:tgtEl>
              </p:cond>
            </p:nextCondLst>
          </p:seq>
        </p:childTnLst>
      </p:cTn>
    </p:par>
  </p:tnLst>
</p:timing>`;
}

// ---------------------------------------------------------------------------
// Find shape ID by name in slide XML
// ---------------------------------------------------------------------------
function findShapeId(slideXml, shapeName) {
  // Match <p:cNvPr id="N" name="shapeName"/>
  const re = new RegExp(`<p:cNvPr\\s+id="(\\d+)"\\s+name="${escapeRegex(shapeName)}"`, 'g');
  const match = re.exec(slideXml);
  if (match) {
    return parseInt(match[1], 10);
  }
  return null;
}

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// ---------------------------------------------------------------------------
// Inject timing XML into slide XML
// ---------------------------------------------------------------------------
function injectTiming(slideXml, timingXml) {
  // Insert <p:timing> before closing </p:sld>
  // If <p:timing> already exists, replace it
  if (slideXml.includes('<p:timing>')) {
    slideXml = slideXml.replace(/<p:timing>[\s\S]*?<\/p:timing>/, timingXml);
  } else {
    slideXml = slideXml.replace('</p:sld>', timingXml + '\n</p:sld>');
  }
  return slideXml;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
async function injectAnimations(pptxPath, manifestPath, outputPath) {
  const pptxBuffer = fs.readFileSync(pptxPath);
  const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));

  const zip = await JSZip.loadAsync(pptxBuffer);

  let injectedCount = 0;

  for (const slideEntry of manifest.slides) {
    const slideFile = `ppt/slides/slide${slideEntry.slideIndex}.xml`;
    const slideZipEntry = zip.file(slideFile);

    if (!slideZipEntry) {
      console.warn(`Slide file not found: ${slideFile}`);
      continue;
    }

    let slideXml = await slideZipEntry.async('string');

    // Resolve shape names to IDs
    const animations = [];
    for (const shape of slideEntry.shapes) {
      const spid = findShapeId(slideXml, shape.name);
      if (spid == null) {
        console.warn(`Shape "${shape.name}" not found in ${slideFile}`);
        continue;
      }
      animations.push({ spid, clicks: shape.clicks });
    }

    if (animations.length === 0) continue;

    const timingXml = generateTimingXml(animations);
    slideXml = injectTiming(slideXml, timingXml);
    zip.file(slideFile, slideXml);
    injectedCount++;
  }

  const outBuffer = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE' });
  fs.writeFileSync(outputPath || pptxPath, outBuffer);

  return injectedCount;
}

// ---------------------------------------------------------------------------
// CLI entry point
// ---------------------------------------------------------------------------
if (require.main === module) {
  const args = process.argv.slice(2);
  if (args.length < 2) {
    console.error('Usage: node animation-injector.js input.pptx manifest.json [output.pptx]');
    process.exit(1);
  }

  const pptxPath = args[0];
  const manifestPath = args[1];
  const outputPath = args[2] || pptxPath;

  if (!fs.existsSync(pptxPath)) {
    console.error(`PPTX file not found: ${pptxPath}`);
    process.exit(1);
  }
  if (!fs.existsSync(manifestPath)) {
    console.error(`Manifest file not found: ${manifestPath}`);
    process.exit(1);
  }

  injectAnimations(pptxPath, manifestPath, outputPath)
    .then(count => {
      console.log(`Injected animations into ${count} slide(s). Output: ${outputPath}`);
    })
    .catch(err => {
      console.error(`Injection error: ${err.message}`);
      process.exit(1);
    });
}

module.exports = { injectAnimations };
